sql = []
sql.append("TRUNCATE menu_items, menu_categories, events CASCADE;\\n")

def esc(s):
    return s.replace("'", "''")

# Categories
cat_lines = []
for c in categories:
    uuid.UUID(c["id"])
    cat_lines.append(f"('{c['id']}', '{esc(c['name_ka'])}', '{esc(c['name_en'])}', '{esc(c['name_uk'])}', {c['order_index']})")
sql.append("INSERT INTO menu_categories (id, name_ka, name_en, name_uk, order_index) VALUES\\n" + ",\\n".join(cat_lines) + ";\\n")

# Items
item_lines = []
for idx, it in enumerate(items):
    uuid.UUID(it["cat"])
    desc_ka = f"'{esc(it['desc_ka'])}'" if "desc_ka" in it else "NULL"
    desc_en = f"'{esc(it['desc_en'])}'" if "desc_en" in it else "NULL"
    desc_uk = f"'{esc(it['desc_uk'])}'" if "desc_uk" in it else "NULL"
    image_url = f"'{esc(it['image_url'])}'" if "image_url" in it else "NULL"
    
    item_lines.append(f"('{it['cat']}', '{esc(it['ka'])}', '{esc(it['en'])}', '{esc(it['uk'])}', {desc_ka}, {desc_en}, {desc_uk}, '{esc(it['price'])}', true, {image_url}, {idx})")

sql.append("INSERT INTO menu_items (category_id, name_ka, name_en, name_uk, description_ka, description_en, description_uk, price, is_available, image_url, order_index) VALUES\\n" + ",\\n".join(item_lines) + ";\\n")

# Events
events = [
    ('Underground Jam', 'Underground Jam', 'Underground Jam', 'ღია მიკროფონი', 'Open Mic Night', 'Відкритий мікрофон', 'ოთხშაბათი', 'Wednesday', 'Середа', '21:00', 0),
    ('Jupiter Nights', 'Jupiter Nights', 'Jupiter Nights', 'DJ სეტი', 'DJ Set', 'DJ сет', 'პარასკევი', 'Friday', "П'ятниця", '23:00', 1),
    ('ცოცხალი მუსიკა', 'Live Bands', 'Живі гурти', 'მოწვეული არტისტები', 'Featured Artists', 'Запрошені არтисти', 'შაბათი', 'Saturday', 'Субота', '22:00', 2)
]
event_lines = []
for ev in events:
    event_lines.append(f"('{esc(ev[0])}', '{esc(ev[1])}', '{esc(ev[2])}', '{esc(ev[3])}', '{esc(ev[4])}', '{esc(ev[5])}', '{esc(ev[6])}', '{esc(ev[7])}', '{esc(ev[8])}', '{esc(ev[9])}', {ev[10]})")

sql.append("INSERT INTO events (title_ka, title_en, title_uk, description_ka, description_en, description_uk, event_day_ka, event_day_en, event_day_uk, event_time, order_index) VALUES\\n" + ",\\n".join(event_lines) + ";\\n")

with open("supabase/seed.sql", "w", encoding="utf-8") as f:
    f.write("\\n".join(sql))

print("Seed SQL generated successfully!")
